mapper.update:
update dish_tag

    dish_id = #{dishId},
    tag_name = #{tagName},
    tag_type = #{tagType},
    weight = #{weight}

where id = #{id}

mapper.select:
select * from dish_tag

    and dish_id = #{dishId}
    and tag_name like concat('%', #{tagName}, '%')
    and tag_type = #{tagType}

order by create_time desc, id desc
